import logging
logger = logging.getLogger(__name__)

import hashlib
import sys
import base64
from pathlib import Path
from .py_confirm import Alert

class IconManager:

    def __init__(self):
        pass

    @staticmethod
    def hash_png(path):
        with open(path, 'rb') as f:
            return hashlib.md5(f.read()).hexdigest()
        
    def sync_icons(self, db_manager):
        icons_dir = Path('frontend/icons')
        icons_dir.mkdir(parents=True, exist_ok=True)

        # Grab all disk icons
        disk_icons = {
            str(p).replace('\\', '/')
            for p in icons_dir.glob('*.png')
        }

        # Get the database icons
        result = db_manager.execute(
            'select icon_path from dim_icon;'
        )
        db_icons = {row[0] for row in result.rows} if result.success else set()

        # Add to DB any PNGs on disk but not in the DB
        for path in disk_icons - db_icons:
            icon_hash = self.hash_png(path)
            db_manager.execute(
                'insert or ignore into dim_icon (icon_path, icon_hash) values (?, ?);',
                (path, icon_hash),
            )
        
        # Remove from DB any records no longer on disk
        for path in db_icons - disk_icons:
            db_manager.execute('delete from dim_icon where icon_path = ?;', (path,))
        
        # Check defaults
        defaults = [
            'frontend/icons/default.png',
            'frontend/icons/default_bust.png',
        ]
        missing = [d for d in defaults if not Path(d).exists()]
        if missing:
            if not Alert().confirm("Defualt icons are missing. They will be restored automatically.\n\nContinue?", "Missing Icon"):
                Alert().info("CAnnot open application without default icons, closing.")
                sys.exit()
            self._restore_defaults(missing, db_manager)
        
    def _restore_defaults(self, missing, db_manager):
        defaults_b64 = {
            'frontend/icons/default.png': r"",
            'frontend/icons/default_bust.png': r"",
        }
        
        for path in missing:
            if path in defaults_b64:
                
                with open(path, 'wb') as f:
                    f.write(base64.b64decode(defaults_b64[path]))
                with open(path, 'rb') as f:
                    icon_hash = hashlib.md5(f.read()).hexdigest()
                db_manager.execute(
                    'insert or ignore into dim_icon (icon_path, icon_hash) values (?, ?);',
                    (path, icon_hash),
                )




